import React, { useEffect, useState } from "react";
import axios from "axios";
import Swal from "sweetalert2";
import { useNavigate } from "react-router-dom";

export default function EditProfile() {
  const navigate = useNavigate();

  const [user, setUser] = useState(null);
  const [name, setName] = useState("");

  const [imageFile, setImageFile] = useState(null);
  const [preview, setPreview] = useState("");

  const [currentPassword, setCurrentPassword] = useState("");
  const [newPassword, setNewPassword] = useState("");

  // ✅ LOAD PROFILE
  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("user") || "{}");

    if (!stored?.email) {
      navigate("/");
      return;
    }

    axios
      .get(`http://localhost:8086/user/profile?email=${stored.email}`)
      .then((res) => {
        setUser(res.data);
        setName(res.data.name);
        setPreview(res.data.profileImage);
      })
      .catch((err) => {
        console.log(err);
        Swal.fire("Error", "Failed to load profile", "error");
      });
  }, [navigate]);

  // ✅ IMAGE PREVIEW
  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setImageFile(file);

    const reader = new FileReader();
    reader.onloadend = () => {
      setPreview(reader.result);
    };
    reader.readAsDataURL(file);
  };

  // ✅ UPDATE PROFILE
  const handleUpdateProfile = async () => {
    try {
      const formData = new FormData();
      formData.append("email", user.email);
      formData.append("name", name);

      if (imageFile) {
        formData.append("image", imageFile);
      }

      const res = await axios.put(
        "http://localhost:8086/user/update-profile",
        formData
      );

      // ✅ backend returns USER object (NOT message)
      Swal.fire("Success", "Profile updated successfully", "success");

      // ✅ sync localStorage with backend
      localStorage.setItem("user", JSON.stringify(res.data));

      navigate("/profile");
    } catch (err) {
      console.log(err);
      Swal.fire(
        "Error",
        err.response?.data?.message || "Update failed",
        "error"
      );
    }
  };

  // ✅ CHANGE PASSWORD
  const handleChangePassword = async () => {
    try {
      const res = await axios.put(
        "http://localhost:8086/user/change-password",
        {
          email: user.email,
          currentPassword,
          newPassword,
        }
      );

      Swal.fire("Success", res.data.message, "success");

      setCurrentPassword("");
      setNewPassword("");
    } catch (err) {
      Swal.fire(
        "Error",
        err.response?.data?.message || "Password update failed",
        "error"
      );
    }
  };

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        Loading profile...
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-indigo-200 via-purple-200 to-pink-200 flex justify-center items-center p-6">

        <div className="backdrop-blur-lg bg-white/30 border border-white/40 shadow-2xl rounded-2xl p-8 w-full max-w-lg">

        <h2 className="text-2xl font-bold text-center text-gray-800 mb-6">
            ✨ Edit Profile
        </h2>

        {/* PROFILE IMAGE */}
        <div className="flex flex-col items-center mb-6">
            <img
            src={
                preview ||
                user.profileImage ||
                `https://ui-avatars.com/api/?name=${user.username}`
            }
            alt="preview"
            className="w-28 h-28 rounded-full object-cover border-4 border-white shadow-lg"
            />

            <input
            type="file"
            accept="image/*"
            onChange={handleImageChange}
            className="mt-4 text-sm text-gray-700 file:mr-4 file:py-2 file:px-4
            file:rounded-full file:border-0 file:text-sm file:font-semibold
            file:bg-indigo-500 file:text-white hover:file:bg-indigo-600"
            />
        </div>

        {/* NAME INPUT */}
        <div className="mb-4">
            <input
            className="w-full px-4 py-2 rounded-lg bg-white/50 border border-white/40 
            focus:outline-none focus:ring-2 focus:ring-indigo-400 transition"
            value={name}
            onChange={(e) => setName(e.target.value)}
            placeholder="Your Name"
            />
        </div>

        {/* SAVE BUTTON */}
        <button
            onClick={handleUpdateProfile}
            className="w-full bg-gradient-to-r from-green-500 to-emerald-600 
            text-white py-2 rounded-lg shadow-md hover:scale-105 transition mb-6"
        >
            Save Changes
        </button>

        {/* DIVIDER */}
        <div className="border-t border-white/40 my-6"></div>

        {/* PASSWORD SECTION */}
        <h3 className="text-lg font-semibold text-gray-800 mb-3">
            🔒 Change Password
        </h3>

        <input
            type="password"
            placeholder="Current Password"
            className="w-full px-4 py-2 mb-3 rounded-lg bg-white/50 border border-white/40 
            focus:outline-none focus:ring-2 focus:ring-indigo-400"
            value={currentPassword}
            onChange={(e) => setCurrentPassword(e.target.value)}
        />

        <input
            type="password"
            placeholder="New Password"
            className="w-full px-4 py-2 mb-4 rounded-lg bg-white/50 border border-white/40 
            focus:outline-none focus:ring-2 focus:ring-indigo-400"
            value={newPassword}
            onChange={(e) => setNewPassword(e.target.value)}
        />

        <button
            onClick={handleChangePassword}
            className="w-full bg-gradient-to-r from-indigo-500 to-purple-600 
            text-white py-2 rounded-lg shadow-md hover:scale-105 transition"
        >
            Update Password
        </button>

        </div>
    </div>
    );
}
